t.script:
var searchInput = document.getElementById('search-name');
if (searchInput) {
    searchInput.addEventListener('input', function() {
        var q = this.value.toLowerCase();
        document.querySelectorAll('.med-card').forEach(function(card) {
            var name = (card.getAttribute('data-name') || '').toLowerCase();
            var spec = (card.getAttribute('data-specialty') || '').toLowerCase();
            card.style.display = (name.indexOf(q) !== -1 || spec.indexOf(q) !== -1) ? '' : 'none';
        });
    });
}

document.addEventListener('DOMContentLoaded', function() {
    if (typeof flatpickr !== 'undefined') {
        flatpickr("#appointment_date", {
            enableTime: true,
            dateFormat: "Y-m-d\\TH:i",
            altInput: true,
            altFormat: "d/m/Y à H:i",
            locale: "fr",
            minDate: "today",
            minTime: "08:00",
            maxTime: "17:00",
            time_24hr: true,
            disable: [ function(date) { return (date.getDay() === 0 || date.getDay() === 6); } ]
        });
    }
});
